def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    import difflib

    # Load the modified ppt
    prs = Presentation(modified_ppt_path)
    # Slide numbers are 1-based
    try:
        slide = prs.slides[1]  # slide 2 (0-based index)
    except IndexError:
        return "Slide 2 does not exist in the modified presentation.", 0.0
    found_old = False
    found_new = False
    for shape in slide.shapes:
        if not shape.has_text_frame:
            continue
        for para in shape.text_frame.paragraphs:
            text = para.text.strip()
            if text == 'Lateral Axis':
                found_old = True
            if text == 'Lateral (Side-to-Side) Axis':
                found_new = True
    if found_new and not found_old:
        return "Bullet text correctly changed to 'Lateral (Side-to-Side) Axis' on slide 2.", 1.0
    if found_new and found_old:
        return "'Lateral (Side-to-Side) Axis' found but old text 'Lateral Axis' still present.", 0.5
    if not found_new and found_old:
        return "'Lateral Axis' still present, no sign of correct new text.", 0.0
    return "Correct text not found and old text not found: unclear or wrong modification.", 0.0

